kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelMinGptNewGeluCustom {
public:
    __aicore__ inline KernelMinGptNewGeluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueueA_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueueB_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(GetBlockIdx());

        // Grid-stride tiling for load balance
        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        // Prefetch first tile
        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            // Prefetch next tile early
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        // Constants for the GELU formula
        const float coeff_cube = 0.044715f;        // coefficient for x^3
        const float coeff_tanh = 0.797884560802865f; // sqrt(2/pi)
        const float half = 0.5f;
        const float one = 1.0f;

        LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        LocalTensor<float> t1 = tmpQueueA_.AllocTensor<float>();   // will hold intermediate results
        LocalTensor<float> t2 = tmpQueueB_.AllocTensor<float>();

        // Step 1: compute x^3
        Mul(t1, xLocal, xLocal, len);  // t1 = x^2
        Mul(t1, t1, xLocal, len);      // t1 = x^3

        // Step 2: 0.044715 * x^3 + x
        Muls(t1, t1, coeff_cube, len); // t1 = 0.044715 * x^3
        Add(t1, t1, xLocal, len);      // t1 = x + 0.044715 * x^3

        // Step 3: multiply by sqrt(2/pi)
        Muls(t2, t1, coeff_tanh, len); // t2 = sqrt(2/pi) * (x + 0.044715 * x^3)

        // Step 4: tanh
        Tanh(t1, t2, len);             // t1 = tanh(...)

        // Step 5: 1.0 + tanh(...)
        Adds(t1, t1, one, len);        // t1 = 1.0 + tanh(...)

        // Step 6: 0.5 * x * (1.0 + tanh(...))
        Mul(yLocal, xLocal, t1, len);  // yLocal = x * (1+tanh)
        Muls(yLocal, yLocal, half, len); // yLocal = 0.5 * x * (1+tanh)

        tmpQueueB_.FreeTensor(t2);
        tmpQueueA_.FreeTensor(t1);
        outQueueY_.EnQue(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    TPipe pipe_;
    TQue<TPosition::VECIN, BUFFER_NUM> inQueueX_;
    TQue<TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    TQue<TPosition::VECCALC, 1> tmpQueueA_;
    TQue<TPosition::VECCALC, 1> tmpQueueB_;

    GlobalTensor<float> xGm_;
    GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
};

extern "C" __global__ __aicore__ void min_gpt_new_gelu_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelMinGptNewGeluCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength);
    op.Process();
}
